  function loadConversation(){try{const saved=rows(JSON.parse(localStorage.getItem(conversationStorageKey())||"[]"));app.messages=saved.filter(m=>m&&["user","assistant","system"].includes(m.role)&&!m.isHtml).slice(-MAX_SAVED_MESSAGES).map(m=>({id:m.id||uid("msg"),role:m.role,text:String(m.text||"").slice(0,12000),at:m.at||new Date().toISOString(),feedback:m.role==="assistant"&&m.feedback!==false,streaming:false}))}catch(_){app.messages=[]}}
  function saveConversation(){try{const safe=app.messages.filter(m=>!m.isHtml&&!m.streaming).slice(-MAX_SAVED_MESSAGES).map(({id,role,text,at,feedback})=>({id,role,text:String(text||"").slice(0,12000),at,feedback}));let json=JSON.stringify(safe);while(json.length>420000&&safe.length>4){safe.splice(0,4);json=JSON.stringify(safe)}localStorage.setItem(conversationStorageKey(),json)}catch(_){}}
