  function loadFallbackLearning(){try{app.learning=rows(JSON.parse(localStorage.getItem(LOCAL_LEARNING_KEY)||"[]"))}catch(_){app.learning=[]}}
  function saveFallbackLearning(){try{let keep=app.learning.slice(-180),json=JSON.stringify(keep);while(json.length>300000&&keep.length>1){keep=keep.slice(Math.max(1,Math.floor(keep.length*.15)));json=JSON.stringify(keep)}localStorage.setItem(LOCAL_LEARNING_KEY,json)}catch(_){}}
  function token(){try{return localStorage.getItem(TOKEN_KEY)||""}catch(_){return ""}}
  function setToken(value){try{value?localStorage.setItem(TOKEN_KEY,value):localStorage.removeItem(TOKEN_KEY)}catch(_){}}

  class BridgeClient {
    async request(path,{method="GET",body,signal,timeout=30000,auth=true}={}){
      const controller = new AbortController();
      const timer = setTimeout(()=>controller.abort(),timeout);
      const onAbort=()=>controller.abort(); signal?.addEventListener?.("abort",onAbort,{once:true});
      try{
        const headers={"Content-Type":"application/json"};if(auth&&token())headers["X-Sakura-Token"]=token();
        const response=await fetch(`${BRIDGE_BASE}${path}`,{method,headers,body:body===undefined?undefined:JSON.stringify(body),signal:controller.signal,cache:"no-store"});
        const text=await response.text();let parsed={};try{parsed=text?JSON.parse(text):{}}catch(_){parsed={message:text}}
        if(!response.ok)throw new Error(parsed.error||parsed.message||`Error local ${response.status}`);return parsed;
      }finally{clearTimeout(timer);signal?.removeEventListener?.("abort",onAbort)}
    }
    status(signal){return this.request("/status",{signal,auth:false,timeout:4500})}
    pair(code,signal){return this.request("/pair",{method:"POST",body:{code,origin:location.origin},signal,auth:false,timeout:7000})}
    models(signal){return this.request("/models",{signal,timeout:8000})}
    intent(payload,signal){return this.request("/intent",{method:"POST",body:payload,signal,timeout:45000})}
    analyze(payload,signal){return this.request("/analyze",{method:"POST",body:payload,signal,timeout:70000})}
    embed(payload,signal){return this.request("/embed",{method:"POST",body:payload,signal,timeout:70000})}
    vaultList(scope="all",signal){return this.request(`/vault?scope=${encodeURIComponent(scope)}`,{signal,timeout:12000})}
    vaultAdd(entry,signal){return this.request("/vault",{method:"POST",body:entry,signal,timeout:70000})}
    vaultDelete(id,signal){return this.request(`/vault/${encodeURIComponent(id)}`,{method:"DELETE",signal,timeout:12000})}
    backup(signal){return this.request("/backup",{method:"POST",body:{},signal,timeout:20000})}
    release(model,signal){return this.request("/release",{method:"POST",body:{model},signal,timeout:18000})}
    async chat(payload,{signal,onToken}={}){
      const controller=new AbortController(),onAbort=()=>controller.abort();signal?.addEventListener?.("abort",onAbort,{once:true});
      const headers={"Content-Type":"application/json","Accept":"text/event-stream"};if(token())headers["X-Sakura-Token"]=token();
      const response=await fetch(`${BRIDGE_BASE}/chat`,{method:"POST",headers,body:JSON.stringify(payload),signal:controller.signal,cache:"no-store"});
      if(!response.ok){const txt=await response.text();throw new Error(txt||`Error local ${response.status}`)}
      if(!response.body){const obj=await response.json();onToken?.(obj.message||"");return obj.message||""}
      const reader=response.body.getReader(),decoder=new TextDecoder();let buffer="",full="";
      try{while(true){const {done,value}=await reader.read();if(done)break;buffer+=decoder.decode(value,{stream:true});let idx;while((idx=buffer.indexOf("\n"))>=0){const line=buffer.slice(0,idx).trim();buffer=buffer.slice(idx+1);if(!line)continue;let obj;try{obj=JSON.parse(line)}catch(_){continue}if(obj.error)throw new Error(obj.error);if(obj.token){full+=obj.token;onToken?.(obj.token)}if(obj.done)break}}}finally{signal?.removeEventListener?.("abort",onAbort);reader.releaseLock?.()}
      return full;
    }
  }
  const bridge = new BridgeClient();

  function sakuraSchema(){const client=sbClient();return client?.schema?.("marketing_app")||null}
  function isMissingSakuraTable(error){const text=String(error?.message||error?.details||"").toLowerCase();return ["42p01","pgrst205","pgrst204"].includes(String(error?.code||"").toLowerCase())||text.includes("sakura_knowledge")&&/(does not exist|schema cache|not found)/.test(text)}
  async function loadSharedKnowledge(){const api=sakuraSchema();if(!api){app.shared.available=false;return[]}try{const result=await api.from("sakura_knowledge").select("id,scope,owner_member_id,area_id,knowledge_type,title,content,analysis,status,version,created_at,updated_at").order("updated_at",{ascending:false}).limit(200);if(result.error)throw result.error;app.shared.available=true;app.shared.error="";return rows(result.data).map(entry=>({id:entry.id,type:entry.knowledge_type||"knowledge",scope:entry.scope,owner_id:entry.owner_member_id,area_id:entry.area_id,title:entry.title,content:entry.content,analysis:entry.analysis||{},status:entry.status,version:entry.version||1,created_at:entry.created_at,updated_at:entry.updated_at,source:"shared"}))}catch(error){if(isMissingSakuraTable(error)){app.shared.available=false;app.shared.error="El aprendizaje compartido todavía no está activado.";return[]}app.shared.available=false;app.shared.error=friendlyError(error);return[]}}
  async function saveSharedKnowledge(entry){const api=sakuraSchema();if(!api)return false;try{const payload={scope:entry.scope,owner_member_id:me().id,area_id:entry.scope==="area"?(me().area_id||null):null,knowledge_type:entry.type||"knowledge",title:entry.title,content:entry.content,analysis:entry.analysis||{},status:"published",version:entry.version||1};const result=await api.from("sakura_knowledge").insert(payload).select("id").single();if(result.error)throw result.error;app.shared.available=true;entry.id=result.data?.id||entry.id;entry.source="shared";entry.status="published";return true}catch(error){if(isMissingSakuraTable(error)){app.shared.available=false;return false}throw error}}
  async function deleteSharedKnowledge(id){const api=sakuraSchema();if(!api)return false;const result=await api.from("sakura_knowledge").delete().eq("id",id);if(result.error)throw result.error;return true}
  async function auditSharedAction(action,result,error=""){const api=sakuraSchema();if(!api)return;try{const payload={request_key:action.id,actor_member_id:me().id||null,actor_role:me().role_code||null,action_name:action.intent,parameters:action.params||{},result:result==="success"?"completed":result==="cancelled"?"cancelled":"error",entity_type:"task",entity_id:String(action.params?.task_id||""),error_message:error||null,sakura_version:VERSION};const response=await api.from("sakura_action_audit").insert(payload);if(response.error&&!isMissingSakuraTable(response.error))console.info("[SAKURA] Auditoría compartida no disponible",response.error.message)}catch(_){}}

  function currentSection(){return document.querySelector("main .section.active, .content .section.active, section.section.active")?.id || document.querySelector("[data-section].active")?.dataset.section || "home"}
  function taskById(id){return rows(data().tasks).find(t=>same(t.id,id))}
  function campaignById(id){return rows(data().campaigns).find(c=>same(c.id,id))}
  function selectedTask(){return taskById(app.lastTaskId) || (currentSection()==="myday" ? myTasks().find(t=>!done(t)) : null)}
  function selectedCampaign(){return campaignById(app.lastCampaignId) || (selectedTask()?.campaign_id ? campaignById(selectedTask().campaign_id) : null)}
  function myTasks(){return rows(data().tasks).filter(t=>same(t.assigned_to,me().id)||rows(t.assignee_ids).some(id=>same(id,me().id)))}
  function contextObject(){const task=selectedTask(),campaign=selectedCampaign(),section=currentSection();return {user:{id:me().id||null,name:me().full_name||"Miembro",role:me().role_code||me().position||"member"},screen:section,task:task?{id:task.id,title:task.title,description:task.description,status:task.status,approval_status:task.approval_status,due_date:task.due_date,due_time:task.due_time,priority:task.priority,observation:task.observation||task.last_comment||task.comment||"",assignee:personName(task.assigned_to),campaign:nameOf(data().campaigns,task.campaign_id),client:nameOf(data().clients,task.client_id)}:null,campaign:campaign?{id:campaign.id,name:campaign.name,status:campaign.status,end_date:campaign.end_date,objective:campaign.objective}:null,counts:{my_open:myTasks().filter(t=>!done(t)&&!awaiting(t)).length,my_review:myTasks().filter(awaiting).length,pending_reviews:manager()?rows(data().tasks).filter(awaiting).length:0},timestamp:new Date().toISOString()}}
  function contextSummary(){const c=contextObject();if(c.task)return `${c.screen} · ${c.task.title} · ${c.task.status||"pendiente"}`;if(c.campaign)return `${c.screen} · ${c.campaign.name}`;return `${c.screen} · ${c.counts.my_open} tareas abiertas`}
