    if(document.documentElement.dataset.sakuraContextHooks==="1")return;
    document.documentElement.dataset.sakuraContextHooks="1";
    document.addEventListener("click",event=>{
      const target=event.target instanceof Element?event.target:null;if(!target)return;
      const taskNode=target.closest("[data-task-id]");if(taskNode?.dataset.taskId)app.lastTaskId=taskNode.dataset.taskId;
      const campaignNode=target.closest("[data-campaign-id]");if(campaignNode?.dataset.campaignId)app.lastCampaignId=campaignNode.dataset.campaignId;
      if(taskNode||campaignNode||target.closest(".v472-menu-item,[data-v472-menu],[data-route],[data-nav],button[onclick*='navTo']"))setTimeout(refreshContext,0);
    },{passive:true,capture:true});
    window.addEventListener("popstate",refreshContext,{passive:true});
