  function openPanel(){buildUI();app.open=true;app.minimized=false;const panel=document.getElementById("sakuraNativePanel");panel.classList.add("open");panel.classList.remove("minimized");const style=window.INBESTIGA_SAKURA_STUDIO?.load?.()||window.INBESTIGA_SAKURA_APPEARANCE?.load?.();if(style){panel.dataset.panelMode=style.panelMode||"normal";panel.dataset.mobileHeight=style.mobileHeight||"70"}document.documentElement.dataset.sakuraPanelOpen="true";const launcher=document.getElementById("sakuraNativeLauncher");launcher?.style.setProperty("opacity","0");launcher?.style.setProperty("pointer-events","none");applyDockLayout();refreshContext();if(!app.messages.length)addAssistant(`Hola${me().full_name?`, ${String(me().full_name).split(" ")[0]}`:""}. Estoy aquí sin tapar tu espacio de trabajo. Puedes hablarme de forma natural, incluso con errores de escritura; conservaré el contexto y te mostraré lo que entendí antes de ejecutar cualquier acción.`,false);checkBridge(false)}
