  function renderQuickActions(){const host=document.getElementById("skQuickActions");if(!host)return;const task=selectedTask();const actions=["Organiza mi día","¿Qué hago primero?","Genera mi reporte de hoy"];if(task)actions.unshift("Explícame esta tarea","Convierte esta tarea en pasos");if(manager())actions.push("Muéstrame entregas pendientes","Crear una tarea");host.innerHTML=actions.map(a=>`<button type="button" data-sk-quick="${escHtml(a)}">${escHtml(a)}</button>`).join("");host.querySelectorAll("[data-sk-quick]").forEach(b=>b.onclick=()=>{document.getElementById("skInput").value=b.dataset.skQuick;sendInput()})}
