  function renderMessages(){const host=document.getElementById("skMessages");if(!host)return;host.innerHTML=app.messages.map(m=>`<article class="sk-message ${m.role}" data-sk-message="${m.id}">${escHtml(m.text)}${m.streaming?'<span class="sk-caret">▋</span>':''}<div class="sk-message-meta">${new Date(m.at).toLocaleTimeString("es-PE",{hour:"2-digit",minute:"2-digit"})}</div>${m.role!=="system"?`<div class="sk-message-actions"><button type="button" data-sk-copy-message="${m.id}">Copiar</button></div>`:""}${m.feedback?`<div class="sk-feedback"><button data-sk-feedback="useful">Me gustó</button><button data-sk-feedback="cold">Más cálida</button><button data-sk-feedback="long">Más breve</button><button data-sk-feedback="wrong">No entendió</button><button data-sk-feedback="correct">Corregir</button></div>`:""}</article>`).join("");host.querySelectorAll("[data-sk-feedback]").forEach(b=>b.onclick=()=>handleFeedback(b.closest("[data-sk-message]")?.dataset.skMessage,b.dataset.skFeedback));host.querySelectorAll("[data-sk-copy-message]").forEach(b=>b.onclick=async()=>{const msg=app.messages.find(m=>m.id===b.dataset.skCopyMessage);if(!msg)return;try{await navigator.clipboard.writeText(msg.text);toast("Mensaje copiado.")}catch(_){toast("No pude copiar el mensaje.")}});host.scrollTop=host.scrollHeight}
  function updateStreamingMessage(message,tokenText){message.text+=tokenText;message.streaming=true;app.lastAssistantText=message.text;renderMessages()}
