  function normalize(text){return String(text||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[’‘]/g,"'").replace(/\s+/g," ").trim()}
  function normalizeNaturalText(text){let value=normalize(text);const builtins={"vcl":"vsl","v c l":"vsl","cleinte":"cliente","clietne":"cliente","estadoceo":"estado ceo","blinder":"blynder"};for(const [from,to] of Object.entries({...builtins,...(app.aliases||{})})){value=value.replace(new RegExp(`\\b${escapeRegExp(normalize(from))}\\b`,"g"),normalize(to))}value=value.replace(/\bx\s*(\d+(?:[.,]\d+)?)\b/g,"$1x").replace(/(\d+(?:[.,]\d+)?)\s*x\b/g,"$1x");return value}
  function levenshtein(a,b){a=String(a||"");b=String(b||"");if(!a.length)return b.length;if(!b.length)return a.length;const row=Array.from({length:b.length+1},(_,i)=>i);for(let i=1;i<=a.length;i++){let prev=row[0];row[0]=i;for(let j=1;j<=b.length;j++){const old=row[j],cost=a[i-1]===b[j-1]?0:1;row[j]=Math.min(row[j]+1,row[j-1]+1,prev+cost);prev=old}}return row[b.length]}
