  function findMember(text){return entityMatch(text,rows(data().members).filter(m=>m.status!=="inactive"),m=>[m.full_name,m.name,m.email?.split("@")[0],m.username])}
  function findClient(text){return entityMatch(text,rows(data().clients),c=>[c.name,c.client_name,c.company_name,c.business_name])}
  function findCampaign(text){return entityMatch(text,rows(data().campaigns),c=>[c.name,c.title])}
  function parseDate(text){const n=normalizeNaturalText(text),base=new Date();if(n.includes("hoy"))return dayKey(base);if(n.includes("manana")){base.setDate(base.getDate()+1);return dayKey(base)}const days={domingo:0,lunes:1,martes:2,miercoles:3,jueves:4,viernes:5,sabado:6};for(const [word,index] of Object.entries(days)){if(n.includes(word)){let delta=(index-base.getDay()+7)%7;if(delta===0)delta=7;base.setDate(base.getDate()+delta);return dayKey(base)}}const match=n.match(/\b(\d{1,2})[\/-](\d{1,2})(?:[\/-](\d{2,4}))?\b/);if(match){const year=match[3]?Number(match[3].length===2?`20${match[3]}`:match[3]):base.getFullYear();return `${year}-${String(match[2]).padStart(2,"0")}-${String(match[1]).padStart(2,"0")}`}return ""}
  function parseTime(text){const n=normalizeNaturalText(text).replace(/\./g,"");const match=n.match(/(?:a\s+las?\s+)?(\d{1,2})(?::(\d{2}))?\s*(am|pm)\b/)||n.match(/(?:a\s+las?\s+)(\d{1,2})(?::(\d{2}))?\b/);if(!match)return"";let hour=Number(match[1]),minute=Number(match[2]||0),period=match[3]||"";if(period==="pm"&&hour<12)hour+=12;if(period==="am"&&hour===12)hour=0;if(hour>23||minute>59)return"";return`${String(hour).padStart(2,"0")}:${String(minute).padStart(2,"0")}`}
