  function escapeRegExp(value){return String(value||"").replace(/[.*+?^${}()|[\]\\]/g,"\\$&")}
  function deriveTaskTitle(text){let s=normalizeNaturalText(text);const speed=parseSpeed(s);if(/velocidad|acelerar/.test(s)&&/video/.test(s))return`Aumentar velocidad del video${/\bvsl\b/.test(s)?" VSL":""}${speed?` a ${speed}`:""}`;s=s.replace(/^sakura\s*[,;:\-]?\s*/i,"").replace(/^.*?\b(?:crea|crear|asigna(?:le)?|asigne(?:s)?|asignar|manda(?:le)?|encarga)\b\s*/i,"").replace(/^(?:una?\s+)?(?:tarea\s+)?(?:para\s+|a\s+)?/i,"").trim();const found=findMember(text);if(found){const names=[found.full_name,...String(found.full_name||"").split(/\s+/).filter(x=>x.length>2)].sort((a,b)=>b.length-a.length);for(const candidate of names)s=s.replace(new RegExp(`^(?:a\\s+)?${escapeRegExp(candidate)}(?:\\s*,?\\s*)?`,"i"),"").trim()}s=s.replace(/^(?:que\s+)?(?:haga|realice|prepare)\s+/i,"").replace(/\b(?:para|antes de|hasta)\s+(?:el\s+)?(?:lunes|martes|miercoles|jueves|viernes|sabado|domingo|hoy|manana).*$/i,"").replace(/\b(?:del?|para el)\s+cliente\s+.+$/i,"").trim();return s?`${s[0].toUpperCase()}${s.slice(1)}`:""}


  async function sendInput(){const input=document.getElementById("skInput"),text=String(input?.value||"").trim();if(!text)return;input.value="";input.style.height="auto";app.lastUserText=text;addMessage("user",text,{feedback:false});setPresence("thinking");document.getElementById("skSend").disabled=true;
    try{const local=localIntent(text);let intent=local;if(app.bridge.ollama&&flags.actions!==false){try{const remote=await bridge.intent({text,context:contextObject(),draft:app.commandDraft,entities:entityCatalog(),allowed_actions:allowedActions(),model:app.bridge.chatModel});if(remote?.intent&&remote.intent!=="chat"){const mergedParams={...(local.parameters||{}),...(remote.parameters||{})};if(remote.parameters?.assigned_to&&!rows(data().members).some(m=>same(m.id,remote.parameters.assigned_to))){const person=findMember(remote.parameters.assigned_to);if(person)mergedParams.assigned_to=person.id}if(remote.parameters?.client_id&&!rows(data().clients).some(c=>same(c.id,remote.parameters.client_id))){const client=findClient(remote.parameters.client_id);if(client)mergedParams.client_id=client.id}intent={...local,...remote,parameters:mergedParams}}else if(local.intent==="chat"&&remote?.intent==="chat")intent=remote}catch(error){console.info("[SAKURA] Intención local de respaldo",error.message)}}
      if(intent.intent!=="chat"){await handleIntent(intent,text);return}await conversationalReply(text)
    }catch(error){if(error.name!=="AbortError")addAssistant(friendlyError(error),false)}finally{document.getElementById("skSend").disabled=false;setPresence(app.bridge.ollama?"idle":"offline")}}

  function allowedActions(){const base=["get_my_day","get_task","search_tasks","get_campaign","get_blockers","generate_daily_report","generate_weekly_report","prepare_delivery","update_progress","add_comment"];if(manager())base.push("get_pending_reviews","get_team_capacity","create_task","assign_task","change_deadline","change_priority","request_correction");return base}
  async function handleIntent(intent,rawText){if(!allowedActions().includes(intent.intent)&&!["task_checklist"].includes(intent.intent)){addAssistant("Esa acción no está habilitada para tu perfil. Puedo ayudarte a preparar una alternativa dentro de tus permisos.");return}
    switch(intent.intent){case"get_my_day":return addAssistant(myDayResponse(!!intent.parameters?.priority));case"get_task":return addAssistant(taskResponse(taskById(intent.parameters?.task_id)||selectedTask()));case"task_checklist":return addAssistant(checklistResponse(taskById(intent.parameters?.task_id)||selectedTask()));case"get_pending_reviews":return addAssistant(pendingReviewsResponse());case"get_blockers":return addAssistant(blockersResponse());case"search_tasks":return addAssistant(searchTasksResponse(intent.parameters?.query||rawText));case"get_campaign":return addAssistant(campaignResponse(campaignById(intent.parameters?.campaign_id)||findCampaign(rawText)||selectedCampaign()));case"get_team_capacity":return addAssistant(teamCapacityResponse());case"generate_daily_report":return generateReport("daily",intent.parameters?.scope||"personal",true);case"generate_weekly_report":return generateReport("weekly",intent.parameters?.scope||"personal",true);case"create_task":return prepareCreateTask(intent.parameters||{},rawText);case"update_progress":return showActionCard("update_progress",intent.parameters||{},rawText);case"change_deadline":return showActionCard("change_deadline",intent.parameters||{},rawText);case"change_priority":return showActionCard("change_priority",intent.parameters||{},rawText);case"add_comment":return showActionCard("add_comment",intent.parameters||{},rawText);case"request_correction":return showActionCard("request_correction",intent.parameters||{},rawText);case"prepare_delivery":window.v66OpenDeliveryModal?.(intent.parameters?.task_id||selectedTask()?.id)||window.v413DeliverTask?.(intent.parameters?.task_id||selectedTask()?.id);return addAssistant("Abrí el formulario de entrega. Revisa la evidencia y confirma desde el flujo oficial de la plataforma.");default:return conversationalReply(rawText)}}
  function myDayResponse(priority=false){const tasks=myTasks().filter(t=>!done(t)),actionable=tasks.filter(t=>!awaiting(t)),late=actionable.filter(overdue),today=actionable.filter(t=>t.due_date===dayKey()),review=tasks.filter(awaiting),observed=actionable.filter(t=>statusKey(t.status)==="observado"||statusKey(t.approval_status)==="observado");const ordered=[...observed,...late,...today,...actionable.filter(t=>!observed.includes(t)&&!late.includes(t)&&!today.includes(t)).sort((a,b)=>String(a.due_date||"9999").localeCompare(String(b.due_date||"9999")))];if(priority){const first=ordered[0];return first?`Empezaría por “${first.title}”. ${observed.includes(first)?"Tiene una corrección solicitada.":late.includes(first)?`Está vencida desde ${first.due_date}.`:today.includes(first)?"Vence hoy.":"Es la siguiente por fecha y prioridad."} Después revisaría ${ordered[1]?`“${ordered[1].title}”`:"el resto de tu agenda"}.`:`Tu agenda no tiene tareas accionables pendientes.`}return `Hoy tienes ${actionable.length} tarea(s) accionable(s): ${today.length} vencen hoy, ${late.length} están vencidas y ${observed.length} requieren corrección. Además, ${review.length} entrega(s) esperan revisión.${ordered[0]?` La siguiente acción recomendada es “${ordered[0].title}”.`:" Tu cola está al día."}`}
  function taskResponse(task){if(!task)return"No tengo una tarea seleccionada. Abre una tarea o dime su nombre.";const pieces=[`“${task.title}” está en estado ${task.status||"pendiente"}.`,`Responsable: ${personName(task.assigned_to)}.`,task.due_date?`Fecha de entrega: ${task.due_date}${task.due_time?` a las ${String(task.due_time).slice(0,5)}`:""}.`:"No tiene fecha de entrega.",task.description?`Objetivo: ${task.description}`:"",task.observation||task.last_comment?`Observación: ${task.observation||task.last_comment}`:""].filter(Boolean);return pieces.join(" ")}
  function checklistResponse(task){if(!task)return"Abre primero una tarea para convertirla en pasos.";let items=[];if(Array.isArray(task.checklist))items=task.checklist.map(x=>typeof x==="string"?x:(x.title||x.text)).filter(Boolean);if(!items.length){const desc=String(task.description||task.title||"");items=desc.split(/[.;\n]/).map(x=>x.trim()).filter(x=>x.length>8).slice(0,6)}if(!items.length)items=["Revisar el objetivo y los archivos de referencia","Confirmar formato, responsable y deadline","Ejecutar el trabajo","Revisar calidad","Preparar evidencia y entregar"];return `Te propongo este checklist:\n${items.map((x,i)=>`${i+1}. ${x}`).join("\n")}`}
  function pendingReviewsResponse(){if(!manager())return"Tu perfil no tiene acceso a la bandeja general de aprobaciones.";const list=rows(data().tasks).filter(t=>awaiting(t)||statusKey(t.status)==="observado");if(!list.length)return"No hay entregas pendientes de revisión.";return `Hay ${list.length} entrega(s) que requieren atención:\n${list.slice(0,8).map(t=>`• ${t.title} — ${personName(t.assigned_to)} — ${t.status}`).join("\n")}`}
  function blockersResponse(){const blocked=myTasks().filter(t=>{const id=t.depends_on_task_id||t.dependency_task_id||t.blocked_by_task_id;return id&&!done(taskById(id))});return blocked.length?`Tienes ${blocked.length} tarea(s) bloqueada(s):\n${blocked.map(t=>`• ${t.title}`).join("\n")}`:"No detecto tareas tuyas bloqueadas por dependencias en los datos cargados."}
  function searchTasksResponse(query=""){const needle=normalize(query).replace(/^(busca|buscar|encuentra|muestrame)\s+(la\s+|las\s+|una\s+)?tareas?\s*/i,"").trim(),pool=manager()?rows(data().tasks):myTasks(),found=pool.filter(t=>!needle||normalize(`${t.title} ${t.description||""} ${t.status||""} ${personName(t.assigned_to)}`).includes(needle)).slice(0,10);return found.length?`Encontré ${found.length} tarea(s):\n${found.map(t=>`• ${t.title} — ${personName(t.assigned_to)} — ${t.status||"pendiente"}${t.due_date?` — ${t.due_date}`:""}`).join("\n")}`:"No encontré tareas autorizadas que coincidan con esa búsqueda."}
  function campaignResponse(campaign){if(!campaign)return"No encontré esa campaña entre los datos que tienes autorizados.";const tasks=rows(data().tasks).filter(t=>same(t.campaign_id,campaign.id)),open=tasks.filter(t=>!done(t)),late=open.filter(overdue),review=tasks.filter(awaiting);return `La campaña “${campaign.name}” está ${campaign.status||"sin estado definido"}. Tiene ${tasks.length} tarea(s): ${open.length} abiertas, ${late.length} vencidas y ${review.length} en revisión.${campaign.objective?` Objetivo: ${campaign.objective}`:""}`}
  function teamCapacityResponse(){if(!manager())return"Tu perfil no tiene acceso a la capacidad general del equipo.";const people=rows(data().members).filter(m=>m.status!=="inactive").map(person=>{const tasks=rows(data().tasks).filter(t=>same(t.assigned_to,person.id)&&!done(t)&&!awaiting(t)),minutes=tasks.reduce((sum,t)=>sum+Number(t.estimated_minutes||t.estimated_hours*60||0),0);return{person,tasks:tasks.length,minutes,late:tasks.filter(overdue).length}}).sort((a,b)=>a.minutes-b.minutes||a.tasks-b.tasks);if(!people.length)return"No hay miembros activos cargados.";return `Capacidad observada con los datos cargados:\n${people.slice(0,10).map(x=>`• ${x.person.full_name}: ${x.tasks} tarea(s), ${Math.round(x.minutes/60*10)/10} h estimadas, ${x.late} vencida(s)`).join("\n")}\nLa plataforma calcula estos datos; SAKURA no califica a las personas.`}
  function relevantLearning(text){const n=normalize(text),words=n.split(/\W+/).filter(w=>w.length>3);return app.learning.map(entry=>({entry,score:words.reduce((s,w)=>s+(normalize(`${entry.title||""} ${entry.content||""}`).includes(w)?1:0),0)})).filter(x=>x.score>0).sort((a,b)=>b.score-a.score).slice(0,4).map(x=>x.entry)}
  async function conversationalReply(text){
    const academy=window.INBESTIGA_SAKURA_ACADEMY;
    try{const academicAnswer=await academy?.answer?.(text);if(academicAnswer?.handled){addAssistant(academicAnswer.text);return}}catch(error){console.info("[SAKURA Academy] Respuesta académica de respaldo",error?.message||error)}
    const academicKnowledge=academy?.search?await academy.search(text,{limit:4}).catch(()=>[]):[];
    if(!app.bridge.ollama){const learned=[...academicKnowledge,...relevantLearning(text)];if(learned.length){const source=learned[0].sourceName||learned[0].source||"Academia de SAKURA";addAssistant(`Según mi conocimiento aprobado: ${String(learned[0].content||"").slice(0,700)}${String(learned[0].content||"").length>700?"…":""}\nFuente: ${source}.`);return}addAssistant(basicCompanionReply(text));return}
    stopResponse();const controller=new AbortController();app.currentAbort=controller;const message=addMessage("assistant","",{feedback:true,streaming:true});setPresence("thinking");const learn=[...academicKnowledge,...relevantLearning(text)].filter((entry,index,list)=>list.findIndex(item=>String(item.id||item.title)===String(entry.id||entry.title))===index).slice(0,6);const payload={model:app.bridge.chatModel,system:personalityPrompt(),messages:app.messages.filter(m=>["user","assistant"].includes(m.role)&&m.id!==message.id&&!m.isHtml).slice(-MAX_HISTORY).map(m=>({role:m.role,content:m.text})),context:{...contextObject(),active_draft:app.commandDraft||null,recent_summary:conversationSummary(),academy_version:academy?.version||null},knowledge:learn.map(x=>({title:x.title,content:x.content,scope:x.scope||"personal",source:x.sourceName||x.source||"SAKURA Academy",formula:x.formula||null})),options:{temperature:app.preferences.tone==="creative"?.7:.38,num_predict:app.preferences.replyLength==="short"?240:app.preferences.replyLength==="long"?760:480},keep_alive:"5m"};
    try{await bridge.chat(payload,{signal:controller.signal,onToken:tokenText=>{setPresence("speaking");updateStreamingMessage(message,tokenText)}});finishStreamingMessage(message)}catch(error){if(error.name==="AbortError"){message.text=message.text||"Respuesta detenida.";finishStreamingMessage(message)}else{app.bridge.ollama=false;updateStatusUI();message.text=friendlyError(error);finishStreamingMessage(message)}}finally{app.currentAbort=null}}
  function conversationSummary(){return app.messages.filter(m=>["user","assistant"].includes(m.role)&&!m.isHtml).slice(-10).map(m=>`${m.role==="user"?"Usuario":"Sakura"}: ${String(m.text||"").slice(0,500)}`).join("\n")}
  function personalityPrompt(){return `Eres SAKURA, compañera de trabajo de INBESTIGA. Conversas en español natural, cálido y profesional, como una asistente humana competente. Comprendes errores ortográficos, frases incompletas, referencias vagas y lenguaje cotidiano sin burlarte. Conservas el hilo, deduces la intención probable y no vuelves a pedir datos ya confirmados. Primero entiende lo que la persona quiere conseguir; no conviertas automáticamente cada frase en una búsqueda. Cuando exista una orden de plataforma, construye la interpretación completa usando el catálogo real y pide solo el dato que realmente impida ejecutarla. Si una deducción es probable pero no segura, indícala brevemente en vez de interrogar. Cuando un nombre coincide con un miembro, cliente o campaña real, prioriza esa entidad y nunca lo inventes como programa. Responde de forma fluida, evita plantillas repetitivas, listas innecesarias y lenguaje de atención al cliente. No te presentas en cada respuesta, no dices que eres una IA y no finges haber ejecutado acciones: solo Marketing Cloud puede confirmar una acción después de verificar que quedó guardada. No inventas datos empresariales. Diferencias hechos, recomendaciones y supuestos. Responde con ${app.preferences.replyLength==="short"?"brevedad":app.preferences.replyLength==="long"?"detalle moderado":"claridad equilibrada"}. Catálogo autorizado: ${JSON.stringify(entityCatalog()).slice(0,9000)}. Borrador activo: ${JSON.stringify(app.commandDraft||{}).slice(0,4000)}. Contexto autorizado: ${compactContext()}`}
  function basicCompanionReply(text){const n=normalize(text);if(/hola|buenos dias|buenas tardes|buenas noches/.test(n))return`Hola${me().full_name?`, ${String(me().full_name).split(" ")[0]}`:""}. ¿Revisamos tus prioridades, una tarea concreta o un reporte?`;if(/renunciar|irme del trabajo|dejar el trabajo/.test(n))return"Parece una decisión importante. Antes de actuar, ¿esto viene acumulándose desde hace tiempo o ocurrió algo hoy? Puedo ayudarte a ordenar la situación, pero la decisión final debe ser tuya.";return"Mi inteligencia local está desconectada, pero todavía puedo ayudarte con tareas, prioridades, reportes y procesos que ya me hayas enseñado. También puedes iniciar el conector local para conversar con mayor libertad."}
  function stopResponse(){app.currentAbort?.abort?.();app.currentAbort=null;speechSynthesis?.cancel?.();setPresence(app.bridge.ollama?"idle":"offline")}
  function friendlyError(error){const text=String(error?.message||error||"");if(/failed to fetch|network|conex|abort|timeout/i.test(text))return"No pude comunicarme con mi inteligencia local. Marketing Cloud sigue funcionando y puedo ayudarte en modo básico.";return text||"No pude completar esa solicitud."}

  function showActionCard(intent,params,rawText){app.pendingAction={id:uid("action"),intent,params:{...params},rawText,confirmed:false};const msg=addMessage("assistant",actionCardMarkup(app.pendingAction),{feedback:false});msg.isHtml=true;renderMessagesWithActions();setPresence("waiting")}
  function renderMessagesWithActions(){const host=document.getElementById("skMessages");if(!host)return;host.innerHTML=app.messages.map(m=>{if(m.isHtml)return`<article class="sk-message assistant sk-rich-message" data-sk-message="${m.id}">${m.text}</article>`;return`<article class="sk-message ${m.role}" data-sk-message="${m.id}">${escHtml(m.text)}${m.streaming?'<span class="sk-caret">▋</span>':''}<div class="sk-message-meta">${new Date(m.at).toLocaleTimeString("es-PE",{hour:"2-digit",minute:"2-digit"})}</div>${m.role!=="system"?`<div class="sk-message-actions"><button type="button" data-sk-copy-message="${m.id}">Copiar</button></div>`:""}${m.feedback?`<div class="sk-feedback"><button data-sk-feedback="useful">Me gustó</button><button data-sk-feedback="cold">Más cálida</button><button data-sk-feedback="long">Más breve</button><button data-sk-feedback="wrong">No entendió</button><button data-sk-feedback="correct">Corregir</button></div>`:""}</article>`}).join("");host.querySelectorAll("[data-sk-feedback]").forEach(b=>b.onclick=()=>handleFeedback(b.closest("[data-sk-message]")?.dataset.skMessage,b.dataset.skFeedback));host.querySelectorAll("[data-sk-copy-message]").forEach(b=>b.onclick=async()=>{const msg=app.messages.find(m=>m.id===b.dataset.skCopyMessage);if(!msg)return;try{await navigator.clipboard.writeText(msg.text);toast("Mensaje copiado.")}catch(_){toast("No pude copiar el mensaje.")}});host.querySelectorAll("[data-sk-action-confirm]").forEach(b=>b.onclick=()=>executeAction(b.dataset.skActionConfirm));host.querySelectorAll("[data-sk-action-cancel]").forEach(b=>b.onclick=()=>cancelAction(b.dataset.skActionCancel));host.scrollTop=host.scrollHeight}
  const baseRenderMessages=renderMessages;renderMessages=function(){if(app.messages.some(m=>m.isHtml))renderMessagesWithActions();else baseRenderMessages()};
  function actionCardMarkup(action){const p=action.params||{},members=rows(data().members).filter(m=>m.status!=="inactive"),clients=rows(data().clients),campaigns=rows(data().campaigns);if(action.intent==="create_task")return`<div class="sk-action-card" data-action-id="${action.id}"><h4>Nueva tarea · vista previa</h4><div class="sk-interpretation"><strong>Entendí:</strong> ${escHtml(taskDraftSummary(p))}${rows(p.interpretation).length?`<br>${rows(p.interpretation).map(escHtml).join(" ")}`:""}</div><div class="sk-field"><label>Título</label><input id="skActTitle" value="${escHtml(p.title||"")}" placeholder="Qué debe realizarse"></div><div class="sk-grid2"><div class="sk-field"><label>Responsable</label><select id="skActAssignee"><option value="">Seleccionar</option>${members.map(m=>`<option value="${escHtml(m.id)}" ${same(m.id,p.assigned_to)?"selected":""}>${escHtml(m.full_name)}</option>`).join("")}</select></div><div class="sk-field"><label>Cliente</label><select id="skActClient"><option value="">Sin cliente</option>${clients.map(c=>`<option value="${escHtml(c.id)}" ${same(c.id,p.client_id)?"selected":""}>${escHtml(c.name||c.client_name||c.company_name||"Cliente")}</option>`).join("")}</select></div><div class="sk-field"><label>Campaña</label><select id="skActCampaign"><option value="">Sin campaña</option>${campaigns.map(c=>`<option value="${escHtml(c.id)}" ${same(c.id,p.campaign_id)?"selected":""}>${escHtml(c.name||c.title)}</option>`).join("")}</select></div><div class="sk-field"><label>Prioridad</label><select id="skActPriority"><option ${p.priority==="media"?"selected":""}>media</option><option ${p.priority==="alta"?"selected":""}>alta</option><option ${p.priority==="urgente"?"selected":""}>urgente</option><option ${p.priority==="baja"?"selected":""}>baja</option></select></div><div class="sk-field"><label>Fecha</label><input id="skActDue" type="date" value="${escHtml(p.due_date||"")}"></div><div class="sk-field"><label>Hora</label><input id="skActDueTime" type="time" value="${escHtml(p.due_time||"")}"></div></div><div class="sk-field"><label>Instrucciones</label><textarea id="skActDescription" placeholder="Describe claramente la corrección o entregable">${escHtml(p.description||action.rawText||"")}</textarea></div><div class="sk-action-actions"><button class="sk-primary" data-sk-action-confirm="${action.id}">Confirmar y asignar</button><button class="sk-secondary" data-sk-action-cancel="${action.id}">Cancelar</button></div><p class="sk-note">La tarea será creada por ${escHtml(me().full_name||"el usuario conectado")} mediante SAKURA. La interpretación puede editarse antes de confirmar.</p></div>`;
    const task=taskById(p.task_id)||selectedTask();return`<div class="sk-action-card" data-action-id="${action.id}"><h4>${escHtml(actionLabel(action.intent))}</h4><div class="sk-action-grid"><div><span>Tarea</span><strong>${escHtml(task?.title||"No seleccionada")}</strong></div><div><span>Solicitante</span><strong>${escHtml(me().full_name||"Usuario")}</strong></div></div>${action.intent==="update_progress"?`<div class="sk-field"><label>Progreso o estado</label><select id="skActStatus"><option value="en_proceso">En proceso</option><option value="corregido">Corregido</option></select></div><div class="sk-field"><label>Comentario</label><textarea id="skActComment">Avance ${Number(p.progress||0)||""}%</textarea></div>`:""}${action.intent==="change_deadline"?`<div class="sk-grid2"><div class="sk-field"><label>Nueva fecha</label><input id="skActDue" type="date" value="${escHtml(p.due_date||"")}"></div><div class="sk-field"><label>Hora</label><input id="skActDueTime" type="time" value="${escHtml(p.due_time||"")}"></div></div>`:""}${action.intent==="change_priority"?`<div class="sk-field"><label>Nueva prioridad</label><select id="skActPriority"><option>media</option><option>alta</option><option>urgente</option><option>baja</option></select></div>`:""}${["add_comment","request_correction"].includes(action.intent)?`<div class="sk-field"><label>Comentario</label><textarea id="skActComment" placeholder="Escribe una indicación clara">${escHtml(p.comment||"")}</textarea></div>`:""}<div class="sk-action-actions"><button class="sk-primary" data-sk-action-confirm="${action.id}">Confirmar acción</button><button class="sk-secondary" data-sk-action-cancel="${action.id}">Cancelar</button></div></div>`}

  function actionLabel(intent){return({update_progress:"Actualizar progreso",change_deadline:"Cambiar deadline",change_priority:"Cambiar prioridad",add_comment:"Agregar comentario",request_correction:"Solicitar corrección"})[intent]||intent}
  function cancelAction(id){if(!app.pendingAction||app.pendingAction.id!==id)return;app.pendingAction=null;app.commandDraft=null;addSystem("Acción cancelada. No se modificó ningún dato.");setPresence(app.bridge.ollama?"idle":"offline")}
  function normalizeRpcPayload(value){if(Array.isArray(value))return value[0]||null;if(typeof value==="string"){try{return JSON.parse(value)}catch(_){return value}}if(value&&typeof value==="object"&&"data" in value&&Object.keys(value).length===1)return normalizeRpcPayload(value.data);return value}
  async function callRpcSafe(name,params){const client=sbClient();if(!client?.rpc)return{data:null,error:new Error("Supabase todavía no está disponible en esta sesión.")};const attempts=[];if(typeof client.schema==="function"){try{const scoped=client.schema("marketing_app");if(scoped?.rpc)attempts.push(scoped)}catch(_){}}attempts.push(client);const seen=new Set();let last={data:null,error:new Error(`No se pudo invocar ${name}.`)};for(const api of attempts){if(!api||seen.has(api))continue;seen.add(api);try{const result=await api.rpc(name,params);if(!result?.error)return result||{data:null,error:null};last=result}catch(error){last={data:null,error}}}return last}
  function createdTaskIdFrom(dataValue){const value=normalizeRpcPayload(dataValue);if(typeof value==="string"&&value.length>8)return value;if(value&&typeof value==="object")return String(value.id||value.task_id||value.created_id||"");return""}
  async function refreshAndFindTask({before,id,title,assigned,due}){for(let attempt=0;attempt<4;attempt++){try{await window.loadAll?.()}catch(_){}const tasks=rows(data().tasks),match=id?tasks.find(t=>same(t.id,id)):tasks.filter(t=>!before.has(String(t.id))).sort((a,b)=>String(b.created_at||b.updated_at||"").localeCompare(String(a.created_at||a.updated_at||""))).find(t=>same(t.assigned_to,assigned)&&normalize(t.title)===normalize(title)&&(!due||same(t.due_date,due)));if(match)return match;if(attempt<3)await sleep(500*(attempt+1))}return null}
  function revealCreatedTask(task){try{const fields=[["v412TaskSearch","input",""],["v412TaskAssignee","change",""],["v412TaskPriority","change",""],["v412TaskScope","change","all"]];fields.forEach(([id,event,value])=>{const el=document.getElementById(id);if(!el)return;el.value=value;el.dispatchEvent(new Event(event,{bubbles:true}))});window.navTo?.("tasks");window.renderTasks?.();requestAnimationFrame(()=>{const card=document.querySelector(`[data-task-id="${CSS.escape(String(task.id))}"]`);if(card){card.classList.add("sk-task-highlight");card.scrollIntoView({behavior:"smooth",block:"center"});setTimeout(()=>card.classList.remove("sk-task-highlight"),2600)}})}catch(_){}}
  async function executeAction(id){const action=app.pendingAction;if(!action||action.id!==id||action.confirmed)return;action.confirmed=true;const buttons=document.querySelectorAll(`[data-action-id="${CSS.escape(id)}"] button`);buttons.forEach(b=>b.disabled=true);setPresence("executing");try{const result=await performAction(action);app.pendingAction=null;app.commandDraft=null;if(result?.taskId)action.params.task_id=result.taskId;addAssistant(typeof result==="string"?result:result?.message||"Acción completada.",false);await recordAction(action,"success");if(result?.task)revealCreatedTask(result.task);refreshContext();setPresence("success");setTimeout(()=>setPresence(app.bridge.ollama?"idle":"offline"),1100)}catch(error){action.confirmed=false;buttons.forEach(b=>b.disabled=false);await recordAction(action,"error",error.message);addAssistant(`No pude ejecutar la acción: ${friendlyError(error)}`,false);setPresence("error");setTimeout(()=>setPresence(app.bridge.ollama?"idle":"offline"),1200)}}

  async function performAction(action){const client=sbClient();if(!client)throw new Error("La conexión de Marketing Cloud no está disponible.");const p=action.params||{};if(action.intent==="create_task"){if(!manager()&&!can("tasks","assign"))throw new Error("Tu perfil no puede asignar tareas a otras personas.");const title=document.getElementById("skActTitle")?.value.trim(),assigned=document.getElementById("skActAssignee")?.value,clientId=document.getElementById("skActClient")?.value||null,campaignId=document.getElementById("skActCampaign")?.value||null,due=document.getElementById("skActDue")?.value||null,dueTime=document.getElementById("skActDueTime")?.value||null,priority=document.getElementById("skActPriority")?.value||"media",description=document.getElementById("skActDescription")?.value.trim();if(!title||!assigned||!due||!description)throw new Error("Completa título, responsable, instrucciones y fecha de entrega.");const assignee=rows(data().members).find(m=>same(m.id,assigned));if(!assignee)throw new Error("El responsable seleccionado ya no está disponible.");const resolvedClient=clientId||(campaignId?campaignById(campaignId)?.client_id||null:null),before=new Set(rows(data().tasks).map(t=>String(t.id)));const payload={p_title:title,p_description:`${description}\n\n[Creada por ${me().full_name||"usuario"} mediante SAKURA ${VERSION}]`,p_assigned_to:assigned,p_client_id:resolvedClient,p_area_id:assignee?.area_id||me().area_id||null,p_campaign_id:campaignId,p_due_date:due,p_due_time:dueTime,p_priority:priority,p_impact:3,p_checklist:[]};const response=await callRpcSafe("ibm_v30_create_task",payload);if(response.error)throw response.error;const returnedId=createdTaskIdFrom(response.data);const created=await refreshAndFindTask({before,id:returnedId,title,assigned,due});if(!created)throw new Error("Supabase recibió la solicitud, pero la tarea no apareció en Marketing Cloud. No la consideraré creada; vuelve a intentarlo o usa el formulario oficial.");window.dispatchEvent(new CustomEvent("inbestiga:task-created",{detail:{taskId:created.id,source:"sakura",assignees:[assigned]}}));return{taskId:created.id,task:created,message:`Tarea “${created.title||title}” creada y verificada en Marketing Cloud. La asigné a ${assignee.full_name} para ${due}${dueTime?` a las ${dueTime}`:""}. Abrí la sección Tareas y la resalté para que puedas comprobarla.`}}

    const task=taskById(p.task_id)||selectedTask();if(!task)throw new Error("Selecciona una tarea antes de ejecutar la acción.");if(action.intent==="update_progress"){if(!same(task.assigned_to,me().id)&&!manager())throw new Error("No puedes actualizar esta tarea.");const status=document.getElementById("skActStatus")?.value||"en_proceso",comment=document.getElementById("skActComment")?.value.trim()||"Actualización mediante SAKURA";const response=await callRpcSafe("ibm_v30_update_task",{p_task_id:task.id,p_status:status,p_evidence_url:task.evidence_url||"",p_quality:null,p_comment:comment});if(response.error)throw response.error;await window.loadAll?.();window.renderTasks?.();return`Actualicé “${task.title}” a ${status.replaceAll("_"," ")}.`}

    if(action.intent==="change_deadline"||action.intent==="change_priority"){if(!manager()&&!can("tasks","manage"))throw new Error("Tu perfil no puede modificar planificación.");const patch=action.intent==="change_deadline"?{due_date:document.getElementById("skActDue")?.value,due_time:document.getElementById("skActDueTime")?.value||null}:{priority:document.getElementById("skActPriority")?.value};if(!Object.values(patch)[0])throw new Error("Selecciona un valor válido.");const response=await callRpcSafe("ibm_v175_patch_record",{p_entity_type:"task",p_entity_id:String(task.id),p_patch:patch});if(response.error)throw response.error;await window.loadAll?.();window.renderTasks?.();return`Actualicé ${action.intent==="change_deadline"?"el deadline":"la prioridad"} de “${task.title}”.`}

    if(action.intent==="add_comment"){const comment=document.getElementById("skActComment")?.value.trim();if(!comment)throw new Error("Escribe el comentario.");const response=await callRpcSafe("ibm_v30_update_task",{p_task_id:task.id,p_status:task.status||"en_proceso",p_evidence_url:task.evidence_url||"",p_quality:null,p_comment:comment});if(response.error)throw response.error;await window.loadAll?.();return`Comentario agregado a “${task.title}”.`}

    if(action.intent==="request_correction"){if(!manager())throw new Error("Tu perfil no puede solicitar correcciones.");const comment=document.getElementById("skActComment")?.value.trim();if(!comment)throw new Error("La indicación de corrección es obligatoria.");const response=await callRpcSafe("ibm_v30_update_task",{p_task_id:task.id,p_status:"observado",p_evidence_url:task.evidence_url||"",p_quality:null,p_comment:comment});if(response.error)throw response.error;await window.loadAll?.();window.renderTasks?.();return`Solicité una corrección en “${task.title}”.`}throw new Error("Acción no implementada de forma segura.")}

  async function recordAction(action,result,error=""){const entry={id:action.id,type:"action",scope:"personal",owner_id:me().id,created_at:new Date().toISOString(),title:action.intent,content:JSON.stringify({actor:me().full_name,role:me().role_code,result,error,parameters:action.params,confirmed:true,version:VERSION}).slice(0,10000)};if(app.bridge.paired)bridge.vaultAdd(entry).catch(()=>{});else{app.learning.push(entry);saveFallbackLearning()}auditSharedAction(action,result,error)}

  function reportData(period="daily",scope="personal"){const end=new Date(),start=new Date(end);if(period==="weekly")start.setDate(end.getDate()-6);else start.setHours(0,0,0,0);const all=rows(data().tasks).filter(t=>scope==="team"&&manager()?true:same(t.assigned_to,me().id));const inRange=t=>{const raw=t.updated_at||t.created_at||t.due_date;if(!raw)return true;const d=new Date(raw);return d>=start&&d<=new Date(end.getTime()+86400000)};const tasks=all.filter(inRange),complete=tasks.filter(done),late=tasks.filter(overdue),review=tasks.filter(awaiting),observed=tasks.filter(t=>statusKey(t.status)==="observado");return{period,scope,start:start.toISOString(),end:end.toISOString(),tasks,complete,late,review,observed,completion:tasks.length?Math.round(complete.length*100/tasks.length):0}}
  function generateReport(period="daily",scope="personal",announce=false){if(scope==="team"&&!manager())scope="personal";const d=reportData(period,scope);const title=`Reporte ${period==="weekly"?"semanal":"diario"} · ${scope==="team"?"Equipo":"Personal"}`;const summary=`Se registran ${d.tasks.length} tareas en el periodo. ${d.complete.length} están completadas, ${d.late.length} vencidas, ${d.review.length} esperan revisión y ${d.observed.length} requieren corrección. El cumplimiento observado es ${d.completion}%.`;app.report={...d,title,summary};renderReports();if(announce){setTab("reports");addAssistant(`Preparé el ${title.toLowerCase()}. Los datos fueron calculados por Marketing Cloud: ${summary}`,false)}return app.report}
  function renderReports(){const host=document.getElementById("skViewReports");if(!host)return;const report=app.report||generateReport("daily","personal",false);host.innerHTML=`<div class="sk-section"><h3>Documentos de SAKURA</h3><p>Los números los calcula Marketing Cloud. SAKURA solo organiza y redacta el resumen.</p><div class="sk-grid2"><div class="sk-field"><label>Periodo</label><select id="skReportPeriod"><option value="daily" ${report.period==="daily"?"selected":""}>Hoy</option><option value="weekly" ${report.period==="weekly"?"selected":""}>Últimos 7 días</option></select></div><div class="sk-field"><label>Alcance</label><select id="skReportScope"><option value="personal">Personal</option>${manager()?'<option value="team" '+(report.scope==="team"?"selected":"")+'>Equipo</option>':''}</select></div></div><div class="sk-action-actions"><button id="skBuildReport" class="sk-primary">Actualizar reporte</button><button id="skPrintReport" class="sk-secondary">PDF / Imprimir</button><button id="skCsvReport" class="sk-secondary">CSV</button></div></div><div class="sk-report-preview"><h2>${escHtml(report.title)}</h2><p>${escHtml(report.summary)}</p><div class="sk-action-grid"><div><span>Tareas</span><strong>${report.tasks.length}</strong></div><div><span>Cumplimiento</span><strong>${report.completion}%</strong></div><div><span>Vencidas</span><strong>${report.late.length}</strong></div><div><span>En revisión</span><strong>${report.review.length}</strong></div></div><table><thead><tr><th>Tarea</th><th>Responsable</th><th>Estado</th><th>Fecha</th></tr></thead><tbody>${report.tasks.slice(0,60).map(t=>`<tr><td>${escHtml(t.title)}</td><td>${escHtml(personName(t.assigned_to))}</td><td>${escHtml(t.status||"")}</td><td>${escHtml(t.due_date||"")}</td></tr>`).join("")}</tbody></table></div>`;document.getElementById("skBuildReport").onclick=()=>generateReport(document.getElementById("skReportPeriod").value,document.getElementById("skReportScope").value,false);document.getElementById("skPrintReport").onclick=printReport;document.getElementById("skCsvReport").onclick=downloadReportCsv}
  function printReport(){const r=app.report;if(!r)return;const w=window.open("","_blank","noopener,noreferrer");if(!w){toast("Permite ventanas emergentes para generar el PDF.");return}w.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>${escHtml(r.title)}</title><style>body{font-family:Arial,sans-serif;margin:35px;color:#171923}h1{font-size:30px}.k{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.k div{border:1px solid #ddd;border-radius:12px;padding:12px}.k strong{display:block;font-size:26px}table{width:100%;border-collapse:collapse;margin-top:20px}th,td{padding:8px;border-bottom:1px solid #ddd;text-align:left;font-size:12px}</style></head><body><h1>${escHtml(r.title)}</h1><p>${escHtml(r.summary)}</p><div class="k"><div>Tareas<strong>${r.tasks.length}</strong></div><div>Cumplimiento<strong>${r.completion}%</strong></div><div>Vencidas<strong>${r.late.length}</strong></div><div>En revisión<strong>${r.review.length}</strong></div></div><table><thead><tr><th>Tarea</th><th>Responsable</th><th>Estado</th><th>Fecha</th></tr></thead><tbody>${r.tasks.map(t=>`<tr><td>${escHtml(t.title)}</td><td>${escHtml(personName(t.assigned_to))}</td><td>${escHtml(t.status||"")}</td><td>${escHtml(t.due_date||"")}</td></tr>`).join("")}</tbody></table><script>window.onload=()=>window.print()<\/script></body></html>`);w.document.close()}
  function downloadReportCsv(){const r=app.report;if(!r)return;const csv=[["Tarea","Responsable","Estado","Fecha","Prioridad"],...r.tasks.map(t=>[t.title,personName(t.assigned_to),t.status,t.due_date,t.priority])].map(row=>row.map(v=>`"${String(v??"").replaceAll('"','""')}"`).join(",")).join("\n");downloadBlob(`sakura_${r.period}_${dayKey()}.csv`,csv,"text/csv;charset=utf-8")}
  function downloadBlob(name,content,type){const blob=new Blob([content],{type}),url=URL.createObjectURL(blob),a=document.createElement("a");a.href=url;a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(url),1000)}

  async function renderLearning(){const host=document.getElementById("skViewLearning");if(!host)return;host.innerHTML=`<div class="sk-section"><h3>Estudio de SAKURA</h3><p>Deposita conocimientos, procedimientos o conversaciones. El aprendizaje personal se guarda en tu bóveda local; el conocimiento de área o empresa puede publicarse con el SQL opcional y los permisos correspondientes.</p><div class="sk-field"><label>Título</label><input id="skLearnTitle" placeholder="Ej. Cómo acompañar una decisión importante"></div><div class="sk-grid2"><div class="sk-field"><label>Tipo</label><select id="skLearnType"><option value="auto">Detectar automáticamente</option><option value="knowledge">Conocimiento</option><option value="conversation">Conversación humana</option><option value="procedure">Procedimiento</option><option value="style">Estilo de conversación</option><option value="avoid">Algo que debe evitar</option></select></div><div class="sk-field"><label>Alcance</label><select id="skLearnScope"><option value="personal">Solo para mí</option>${manager()?'<option value="area">Mi área</option>':''}${director()?'<option value="enterprise">Toda la empresa</option>':''}</select></div></div><div class="sk-field"><label>Texto para estudiar</label><textarea id="skLearnText" placeholder="Pega aquí el texto, conversación, manual o respuesta modelo…"></textarea></div><div class="sk-action-actions"><button id="skStudy" class="sk-primary">Analizar e incorporar</button><button id="skImportText" class="sk-secondary">Importar TXT / JSON</button><input id="skImportFile" class="sk-hidden" type="file" accept=".txt,.json,text/plain,application/json"></div><p class="sk-note">El aprendizaje es supervisado: un texto no puede cambiar permisos ni convertirse en una instrucción del sistema.</p></div><div class="sk-section"><h3>Aprendizajes sugeridos</h3><p>SAKURA busca repeticiones en las tareas ya cargadas. Nunca convierte un único caso en una regla.</p><div id="skProposalList" class="sk-list"><div class="sk-empty">Analizando patrones útiles…</div></div></div><div class="sk-section"><h3>Lo que SAKURA sabe de mí</h3><div id="skKnowledgeList" class="sk-list"><div class="sk-empty">Cargando biblioteca…</div></div><div class="sk-action-actions"><button id="skRefreshLearning" class="sk-secondary">Actualizar</button><button id="skBackupLearning" class="sk-secondary">Crear respaldo</button></div></div>`;document.getElementById("skStudy").onclick=studyText;document.getElementById("skImportText").onclick=()=>document.getElementById("skImportFile").click();document.getElementById("skImportFile").onchange=importLearningFile;document.getElementById("skRefreshLearning").onclick=loadLearningLibrary;document.getElementById("skBackupLearning").onclick=createBackup;renderPatternProposals();await loadLearningLibrary()}
  async function saveLearningEntry(entry){if(entry.scope!=="personal"&&await saveSharedKnowledge(entry))return"shared";if(app.bridge.paired){await bridge.vaultAdd(entry);return"bridge"}app.learning.push(entry);saveFallbackLearning();return"browser"}
  function detectPatternProposals(){const ignored=new Set(["para","con","una","las","los","del","por","que","esta","este","tarea","corregir","crear","hacer"]),groups=new Map();for(const task of rows(data().tasks)){const assignee=task.assigned_to;if(!assignee)continue;const words=normalize(task.title).split(/\W+/).filter(w=>w.length>4&&!ignored.has(w));for(const word of new Set(words)){const key=`${assignee}:${word}`,current=groups.get(key)||{assignee,word,count:0,samples:[]};current.count++;if(current.samples.length<3)current.samples.push(task.title);groups.set(key,current)}}return[...groups.values()].filter(x=>x.count>=3).sort((a,b)=>b.count-a.count).slice(0,8).map(x=>({id:`pattern-${x.assignee}-${x.word}`,assignee:x.assignee,title:`Patrón de tareas: ${x.word}`,content:`${personName(x.assignee)} recibe con frecuencia tareas relacionadas con “${x.word}”. Antes de asignarlas, conviene confirmar instrucciones, formato, evidencia y deadline. Ejemplos: ${x.samples.join(" | ")}`,sample_count:x.count}))}
  function renderPatternProposals(){const host=document.getElementById("skProposalList");if(!host)return;app.proposals=detectPatternProposals().filter(p=>!app.learning.some(e=>e.pattern_id===p.id));host.innerHTML=app.proposals.length?app.proposals.map(p=>`<article class="sk-list-item"><strong>${escHtml(p.title)}</strong><span>${p.sample_count} repeticiones detectadas</span><span>${escHtml(p.content.slice(0,180))}</span><div class="sk-list-actions"><button class="sk-primary" data-sk-proposal-approve="${escHtml(p.id)}">Aprobar para mí</button>${manager()?`<button class="sk-secondary" data-sk-proposal-area="${escHtml(p.id)}">Aprobar para el área</button>`:""}<button class="sk-secondary" data-sk-proposal-dismiss="${escHtml(p.id)}">Descartar</button></div></article>`).join(""):'<div class="sk-empty">No hay patrones con al menos tres repeticiones que requieran revisión.</div>';host.querySelectorAll("[data-sk-proposal-approve]").forEach(b=>b.onclick=()=>approvePattern(b.dataset.skProposalApprove,"personal"));host.querySelectorAll("[data-sk-proposal-area]").forEach(b=>b.onclick=()=>approvePattern(b.dataset.skProposalArea,"area"));host.querySelectorAll("[data-sk-proposal-dismiss]").forEach(b=>b.onclick=()=>{app.proposals=app.proposals.filter(p=>p.id!==b.dataset.skProposalDismiss);renderPatternProposals()})}
  async function approvePattern(id,scope){const proposal=app.proposals.find(p=>p.id===id);if(!proposal)return;const entry={id:uid("learn"),type:"workflow_pattern",scope,owner_id:me().id,area_id:me().area_id||null,title:proposal.title,content:proposal.content,analysis:{sample_count:proposal.sample_count},pattern_id:proposal.id,created_at:new Date().toISOString(),status:scope==="personal"?"active":"published",version:1};try{await saveLearningEntry(entry);app.learning.push(entry);toast(scope==="area"?"Patrón publicado para el área.":"Patrón guardado para tu perfil.");renderPatternProposals();await loadLearningLibrary()}catch(error){toast(friendlyError(error))}}

  async function studyText(){const title=document.getElementById("skLearnTitle").value.trim()||"Aprendizaje sin título",content=document.getElementById("skLearnText").value.trim(),type=document.getElementById("skLearnType").value,scope=document.getElementById("skLearnScope").value;if(content.length<20){toast("Pega un texto más completo.");return}const button=document.getElementById("skStudy");button.disabled=true;button.textContent="Estudiando…";try{let analysis={type:type==="auto"?(content.match(/^[^\n:]{1,40}:\s/m)?"conversation":"knowledge"):type,topics:content.toLowerCase().split(/\W+/).filter(w=>w.length>5).slice(0,12),patterns:[]};if(app.bridge.ollama){try{analysis=await bridge.analyze({model:app.bridge.chatModel,title,content:content.slice(0,24000),requested_type:type,scope,user:{id:me().id,name:me().full_name,role:me().role_code}})}catch(error){console.info("[SAKURA] Análisis básico",error.message)}}const entry={id:uid("learn"),type:analysis.type||type,scope,owner_id:me().id,area_id:me().area_id||null,title,content,analysis,created_at:new Date().toISOString(),status:scope==="personal"?"active":"pending_review",version:1};const savedAt=await saveLearningEntry(entry);if(!app.learning.some(x=>same(x.id,entry.id)))app.learning.push(entry);document.getElementById("skLearnText").value="";document.getElementById("skLearnTitle").value="";toast(scope==="personal"?"SAKURA incorporó el aprendizaje.":savedAt==="shared"?"Aprendizaje publicado para su alcance autorizado.":"Aprendizaje guardado localmente; activa el SQL opcional para compartirlo.");await loadLearningLibrary()}catch(error){toast(friendlyError(error))}finally{button.disabled=false;button.textContent="Analizar e incorporar"}}
  async function importLearningFile(event){const file=event.target.files?.[0];if(!file)return;try{const text=await file.text();if(file.name.toLowerCase().endsWith(".json")){const parsed=JSON.parse(text);document.getElementById("skLearnText").value=typeof parsed==="string"?parsed:JSON.stringify(parsed,null,2)}else document.getElementById("skLearnText").value=text;document.getElementById("skLearnTitle").value=file.name.replace(/\.[^.]+$/,"")}catch(error){toast("No se pudo leer el archivo.")}finally{event.target.value=""}}
  async function loadLearningLibrary(){const list=document.getElementById("skKnowledgeList");if(!list)return;try{let local=[];if(app.bridge.paired){const result=await bridge.vaultList("all");local=rows(result.entries)}else{loadFallbackLearning();local=app.learning.filter(e=>e.source!=="shared")}const shared=await loadSharedKnowledge(),combined=[...shared,...local],dedup=new Map();combined.forEach(entry=>dedup.set(String(entry.id),entry));app.learning=[...dedup.values()];const visible=app.learning.filter(e=>same(e.owner_id,me().id)||e.scope==="enterprise"||e.scope==="area"&&same(e.area_id,me().area_id));const sharedNote=app.shared.available===false?`<div class="sk-note">${escHtml(app.shared.error||"El conocimiento compartido no está activado; el aprendizaje personal sigue funcionando.")}</div>`:"";list.innerHTML=sharedNote+(visible.length?visible.slice().sort((a,b)=>String(b.updated_at||b.created_at).localeCompare(String(a.updated_at||a.created_at))).slice(0,80).map(e=>`<article class="sk-list-item"><strong>${escHtml(e.title||"Aprendizaje")}</strong><span>${escHtml(e.type||"knowledge")} · ${escHtml(e.scope||"personal")} · ${escHtml(e.status||"active")}${e.source==="shared"?" · compartido":""}</span><span>${escHtml(String(e.content||"").slice(0,150))}${String(e.content||"").length>150?"…":""}</span><div class="sk-list-actions"><button class="sk-secondary" data-sk-learn-delete="${escHtml(e.id)}">Eliminar</button></div></article>`).join(""):'<div class="sk-empty">Todavía no hay aprendizajes guardados para este perfil.</div>');list.querySelectorAll("[data-sk-learn-delete]").forEach(b=>b.onclick=()=>deleteLearning(b.dataset.skLearnDelete))}catch(error){list.innerHTML=`<div class="sk-empty">${escHtml(friendlyError(error))}</div>`}}
  async function deleteLearning(id){const entry=app.learning.find(x=>same(x.id,id));if(entry?.source==="shared")await deleteSharedKnowledge(id);else if(app.bridge.paired)await bridge.vaultDelete(id);else{app.learning=app.learning.filter(x=>!same(x.id,id));saveFallbackLearning()}await loadLearningLibrary()}
  async function createBackup(){try{if(app.bridge.paired){const result=await bridge.backup();toast(`Respaldo creado: ${result.file||"bóveda local"}`)}else downloadBlob(`sakura_aprendizaje_${dayKey()}.json`,JSON.stringify(app.learning,null,2),"application/json")}catch(error){toast(friendlyError(error))}}
  async function handleFeedback(messageId,type){const message=app.messages.find(m=>m.id===messageId);if(!message)return;if(type==="useful"){await saveCorrection({kind:"positive",question:app.lastUserText,response:message.text});toast("Gracias. Guardé esta respuesta como ejemplo útil.");return}if(type==="cold"){app.preferences.tone="warm";savePrefs();toast("Ajusté tu preferencia hacia respuestas más cálidas.");return}if(type==="long"){app.preferences.replyLength="short";savePrefs();toast("A partir de ahora priorizaré respuestas más breves.");return}const correction=await askText(type==="correct"?"¿Cómo debería haber respondido?":"¿Qué entendí mal y cómo debería responder?","");if(correction)await saveCorrection({kind:type,question:app.lastUserText,response:message.text,correction})}
  async function saveCorrection(payload){const entry={id:uid("correction"),type:"correction",scope:"personal",owner_id:me().id,title:`Corrección · ${String(payload.question||"").slice(0,70)}`,content:JSON.stringify(payload),created_at:new Date().toISOString(),status:"active"};await saveLearningEntry(entry);app.learning.push(entry)}
  async function askText(title,value=""){if(window.premiumInputModal)return window.premiumInputModal({title,subtitle:"Este aprendizaje afectará solo a tu perfil.",label:"Respuesta correcta",placeholder:"Escribe cómo debería responder Sakura…",confirmLabel:"Guardar aprendizaje",required:true,defaultValue:value});return prompt(title,value)}


  function teamInitials(name){return String(name||"IB").split(/\s+/).filter(Boolean).slice(0,2).map(x=>x[0]).join("").toUpperCase()}
  function teamPartners(){const ids=new Set();rows(data().messages).forEach(m=>{if(same(m.sender_id,me().id))ids.add(m.recipient_id);if(same(m.recipient_id,me().id))ids.add(m.sender_id)});rows(data().members).filter(m=>!same(m.id,me().id)&&m.status!=="inactive").forEach(m=>ids.add(m.id));return [...ids].map(id=>rows(data().members).find(m=>same(m.id,id))).filter(Boolean)}
  function messagesWith(partnerId){return rows(data().messages).filter(m=>(same(m.sender_id,partnerId)&&same(m.recipient_id,me().id))||(same(m.sender_id,me().id)&&same(m.recipient_id,partnerId))).sort((a,b)=>new Date(a.created_at)-new Date(b.created_at))}
  function lastMessageWith(partnerId){return messagesWith(partnerId).at(-1)||null}
  function unreadWith(partnerId){return messagesWith(partnerId).filter(m=>same(m.recipient_id,me().id)&&!m.read_at).length}
  function renderTeamMessages(){const host=document.getElementById("skViewMessages");if(!host)return;const query=normalize(app.teamMessages.query),partners=teamPartners().filter(p=>!query||normalize(p.full_name||p.name||"").includes(query));if(!app.teamMessages.partnerId||!partners.some(p=>same(p.id,app.teamMessages.partnerId)))app.teamMessages.partnerId=partners[0]?.id||teamPartners()[0]?.id||"";const partner=rows(data().members).find(m=>same(m.id,app.teamMessages.partnerId)),thread=partner?messagesWith(partner.id):[];host.innerHTML=`<div class="sk-section"><h3>Mensajes del equipo</h3><p>Esta pestaña pertenece a Marketing Cloud y funciona aunque Ollama o el puente local estén apagados.</p></div><div class="sk-team-messages"><section class="sk-team-sidebar"><div class="sk-team-search"><input id="skTeamSearch" value="${escHtml(app.teamMessages.query)}" placeholder="Buscar miembro…"></div><div class="sk-team-list">${partners.map(p=>{const last=lastMessageWith(p.id),unread=unreadWith(p.id);return`<button type="button" class="sk-team-person ${same(p.id,app.teamMessages.partnerId)?"active":""}" data-sk-team-partner="${escHtml(p.id)}"><span class="sk-team-avatar" style="background:${escHtml(p.profile_color||'#6e26f6')}">${p.avatar_data_url?`<img src="${escHtml(p.avatar_data_url)}" alt="">`:escHtml(teamInitials(p.full_name))}</span><span><strong>${escHtml(p.full_name||p.name||"Miembro")}</strong><small>${escHtml(last?.text_content||"Sin mensajes todavía").slice(0,58)}</small></span>${unread?`<i class="sk-team-unread">${unread}</i>`:""}</button>`}).join("")||'<div class="sk-team-empty">No hay miembros disponibles.</div>'}</div></section><section class="sk-team-thread">${partner?`<header class="sk-team-head"><div><strong>${escHtml(partner.full_name||partner.name)}</strong><small style="display:block;color:var(--sk-muted);margin-top:3px">Conversación real del equipo</small></div><button type="button" class="sk-secondary" id="skOpenFullMessages">Abrir en Mensajes</button></header><div class="sk-team-body" id="skTeamBody">${thread.map(m=>`<div class="sk-team-bubble ${same(m.sender_id,me().id)?"out":"in"}">${m.is_urgent?'<strong style="display:block;margin-bottom:4px">Urgente</strong>':''}${escHtml(m.text_content||"")}<time>${new Date(m.created_at).toLocaleString("es-PE")}${m.read_at?" · leído":""}</time></div>`).join("")||'<div class="sk-team-empty">Todavía no hay mensajes. Escribe el primero.</div>'}</div><footer class="sk-team-compose"><textarea id="skTeamDraft" placeholder="Escribe un mensaje para ${escHtml(partner.full_name||partner.name)}…"></textarea><div class="sk-team-compose-actions"><button type="button" class="sk-secondary" id="skTeamWarm" ${app.bridge.ollama?"":"disabled"}>Más cálido</button><button type="button" class="sk-secondary" id="skTeamShort" ${app.bridge.ollama?"":"disabled"}>Más breve</button><button type="button" class="sk-secondary" id="skTeamCorrect" ${app.bridge.ollama?"":"disabled"}>Corregir</button><button type="button" class="sk-secondary" id="skTeamAttach">Adjuntar desde Mensajes</button><span class="spacer"></span><label style="display:flex;align-items:center;gap:6px;font-size:10px"><input id="skTeamUrgent" type="checkbox"> Urgente</label><button type="button" class="sk-primary" id="skTeamSend">Enviar</button></div></footer>`:'<div class="sk-team-empty">Selecciona a un miembro para abrir la conversación.</div>'}</section></div>`;
    host.querySelectorAll("[data-sk-team-partner]").forEach(b=>b.onclick=()=>{app.teamMessages.partnerId=b.dataset.skTeamPartner;renderTeamMessages()});const search=host.querySelector("#skTeamSearch");if(search)search.oninput=()=>{app.teamMessages.query=search.value;renderTeamMessages()};host.querySelector("#skOpenFullMessages")?.addEventListener("click",()=>{window.navTo?.("messages");try{document.getElementById("msgTo").value=app.teamMessages.partnerId;window.renderMessages?.(app.teamMessages.partnerId)}catch(_){}});host.querySelector("#skTeamAttach")?.addEventListener("click",()=>{toast("Los adjuntos se gestionan en el módulo Mensajes para reutilizar su flujo seguro.");window.navTo?.("messages")});host.querySelector("#skTeamSend")?.addEventListener("click",sendTeamMessage);host.querySelector("#skTeamWarm")?.addEventListener("click",()=>rewriteTeamDraft("más cálido"));host.querySelector("#skTeamShort")?.addEventListener("click",()=>rewriteTeamDraft("más breve"));host.querySelector("#skTeamCorrect")?.addEventListener("click",()=>rewriteTeamDraft("corrige la ortografía y claridad"));const body=host.querySelector("#skTeamBody");if(body)body.scrollTop=body.scrollHeight;app.teamMessages.lastRenderedAt=Date.now()}
  async function rewriteTeamDraft(mode){const input=document.getElementById("skTeamDraft"),text=String(input?.value||"").trim();if(!text)return toast("Escribe primero el mensaje que deseas mejorar.");if(!app.bridge.ollama)return toast("Ollama está apagado. Puedes enviar el mensaje sin utilizar SAKURA.");if(app.teamMessages.rewriting)return;app.teamMessages.rewriting=true;try{let full="";await bridge.chat({model:app.bridge.chatModel,messages:[{role:"system",content:"Reescribe mensajes laborales en español natural. Devuelve únicamente el mensaje final, sin explicar."},{role:"user",content:`Haz este mensaje ${mode}: ${text}`}],context:compactContext(),knowledge:[],keep_alive:"2m"},{onToken:t=>{full+=t}});if(full.trim())input.value=full.trim()}catch(error){toast(friendlyError(error))}finally{app.teamMessages.rewriting=false}}
  async function sendTeamMessage(){const partnerId=app.teamMessages.partnerId,input=document.getElementById("skTeamDraft"),text=String(input?.value||"").trim(),urgent=!!document.getElementById("skTeamUrgent")?.checked;if(!partnerId)return toast("Selecciona un miembro.");if(!text)return toast("Escribe un mensaje.");if(app.teamMessages.sending)return;const partner=rows(data().members).find(m=>same(m.id,partnerId));let confirmed=true;try{if(typeof window.premiumConfirmModal==="function")confirmed=await window.premiumConfirmModal({title:`Enviar mensaje a ${partner?.full_name||"este miembro"}`,subtitle:"Este mensaje saldrá de tu perfil real.",preview:`<div class="modal-preview">${escHtml(text)}</div>`,confirmLabel:"Enviar",cancelLabel:"Cancelar"})}catch(_){confirmed=confirm(`Este mensaje será enviado a ${partner?.full_name||"el miembro"}. ¿Continuar?`)}if(!confirmed)return;app.teamMessages.sending=true;const btn=document.getElementById("skTeamSend");if(btn){btn.disabled=true;btn.textContent="Enviando…"}try{const client=sbClient();if(!client?.rpc)throw new Error("Supabase no está disponible.");const {error}=await client.rpc("ibm_v33_send_message",{p_recipient_id:partnerId,p_text_content:text,p_is_urgent:urgent});if(error)throw error;input.value="";const optimistic={id:uid("msgteam"),sender_id:me().id,recipient_id:partnerId,text_content:text,is_urgent:urgent,created_at:new Date().toISOString(),read_at:null,__sakuraOptimistic:true};if(!Array.isArray(data().messages))data().messages=[];data().messages.push(optimistic);renderTeamMessages();toast("Mensaje enviado.");setTimeout(()=>window.safeSync?.("sakura_team_message"),250)}catch(error){toast(`No se pudo enviar: ${friendlyError(error)}`)}finally{app.teamMessages.sending=false;if(btn){btn.disabled=false;btn.textContent="Enviar"}}}

  function renderSettings(){const host=document.getElementById("skViewSettings");if(!host)return;const voices=speechSynthesis?.getVoices?.()||[];host.innerHTML=`<div class="sk-section"><h3>Motor local</h3><div class="sk-health-row"><span><i class="sk-dot ${app.bridge.connected?"":"off"}"></i>Conector local</span><strong>${app.bridge.connected?"Disponible":"Desconectado"}</strong></div><div class="sk-health-row"><span><i class="sk-dot ${app.bridge.ollama?"":"warn"}"></i>Ollama</span><strong>${app.bridge.ollama?"Activo":"Modo básico"}</strong></div><div class="sk-field"><label>Código de emparejamiento</label><input id="skPairCode" placeholder="Código mostrado al iniciar SAKURA Local"></div><div class="sk-action-actions"><button id="skCheckBridge" class="sk-secondary">Comprobar</button><button id="skPairBridge" class="sk-primary">Emparejar</button><button id="skReleaseModel" class="sk-secondary">Liberar modelo</button></div><div class="sk-grid2"><div class="sk-field"><label>Modelo conversacional</label><select id="skChatModel">${modelOptions(app.bridge.chatModel)}</select></div><div class="sk-field"><label>Modelo semántico</label><select id="skEmbedModel">${modelOptions(app.bridge.embedModel)}</select></div></div><p class="sk-note">El conector escucha solo en 127.0.0.1. No recibe credenciales de Supabase ni ejecuta comandos del sistema.</p></div><div class="sk-section"><h3>Panel y apariencia</h3><div class="sk-grid2"><div class="sk-field"><label>Modo del panel</label><select id="skPanelMode"><option value="normal">Normal</option><option value="compact">Compacto</option><option value="orb">Solo esfera</option></select></div><div class="sk-field"><label>Altura en móvil</label><select id="skMobileHeight"><option value="35">35 %</option><option value="70">70 %</option><option value="100">Pantalla completa</option></select></div></div><div class="sk-action-actions"><button id="skOpenPersonalStudio" class="sk-secondary">Personalizar en Diseño</button></div></div><div class="sk-section"><h3>Voz de SAKURA</h3><div class="sk-field"><label>Voz</label><select id="skVoiceName"><option value="">Automática</option>${voices.filter(v=>/^es/i.test(v.lang)).map(v=>`<option value="${escHtml(v.name)}" ${v.name===app.preferences.voiceName?"selected":""}>${escHtml(v.name)} · ${escHtml(v.lang)}</option>`).join("")}</select></div><div class="sk-grid2"><div class="sk-field"><label>Estilo</label><select id="skVoiceTone"><option value="warm">Cálida</option><option value="calm">Serena</option><option value="close">Cercana</option><option value="executive">Ejecutiva</option></select></div><div class="sk-field"><label>Longitud</label><select id="skReplyLength"><option value="short">Breve</option><option value="balanced">Equilibrada</option><option value="long">Detallada</option></select></div></div><div class="sk-action-actions"><button id="skToggleVoice" class="${app.preferences.voice?"sk-primary":"sk-secondary"}">${app.preferences.voice?"Voz activada":"Activar voz"}</button><button id="skTestVoice" class="sk-secondary">Escuchar prueba</button></div></div>`;document.getElementById("skCheckBridge").onclick=()=>checkBridge(true);document.getElementById("skPairBridge").onclick=pairBridge;document.getElementById("skReleaseModel").onclick=releaseModel;document.getElementById("skChatModel").onchange=e=>{app.bridge.chatModel=e.target.value};document.getElementById("skEmbedModel").onchange=e=>{app.bridge.embedModel=e.target.value};document.getElementById("skVoiceName").onchange=e=>{app.preferences.voiceName=e.target.value;savePrefs()};document.getElementById("skVoiceTone").value=app.preferences.tone;document.getElementById("skVoiceTone").onchange=e=>{app.preferences.tone=e.target.value;savePrefs()};document.getElementById("skReplyLength").value=app.preferences.replyLength;document.getElementById("skReplyLength").onchange=e=>{app.preferences.replyLength=e.target.value;savePrefs()};document.getElementById("skToggleVoice").onclick=()=>{app.preferences.voice=!app.preferences.voice;savePrefs();renderSettings()};document.getElementById("skTestVoice").onclick=()=>speak("Hola. Soy Sakura. Te acompañaré con calma, claridad y una voz bastante menos aterradora.",true);const currentStyle=window.INBESTIGA_SAKURA_STUDIO?.load?.()||{};const panelMode=document.getElementById("skPanelMode"),mobileHeight=document.getElementById("skMobileHeight");if(panelMode){panelMode.value=currentStyle.panelMode||"normal";panelMode.onchange=()=>{const style={...currentStyle,panelMode:panelMode.value};window.INBESTIGA_SAKURA_STUDIO?.apply?.(style);document.getElementById("sakuraNativePanel").dataset.panelMode=panelMode.value}}if(mobileHeight){mobileHeight.value=currentStyle.mobileHeight||"70";mobileHeight.onchange=()=>{document.getElementById("sakuraNativePanel").dataset.mobileHeight=mobileHeight.value}}document.getElementById("skOpenPersonalStudio").onclick=()=>{window.INBESTIGA_UNIFIED_VISUAL_EDITOR?.open?.("sakura")||window.navTo?.("designStudio")}}
  function modelOptions(selected){const models=app.bridge.models.length?app.bridge.models:[{name:"gemma3:4b"},{name:"embeddinggemma"}];return models.map(m=>`<option value="${escHtml(m.name||m.model)}" ${(m.name||m.model)===selected?"selected":""}>${escHtml(m.name||m.model)}</option>`).join("")}
  async function checkBridge(showToast=true){app.bridge.lastCheck=Date.now();const controller=new AbortController();try{const s=await bridge.status(controller.signal);app.bridge.connected=true;app.bridge.paired=!!s.paired&&!!token();app.bridge.ollama=!!s.ollama;app.bridge.error="";if(app.bridge.paired){const result=await bridge.models(controller.signal);app.bridge.models=rows(result.models);app.bridge.ollama=!!result.ollama;if(!app.bridge.models.some(m=>(m.name||m.model)===app.bridge.chatModel)){app.bridge.chatModel=app.bridge.models.find(m=>!/embed/i.test(m.name||m.model||""))?.name||app.bridge.chatModel}if(!app.bridge.models.some(m=>(m.name||m.model)===app.bridge.embedModel)){app.bridge.embedModel=app.bridge.models.find(m=>/embed/i.test(m.name||m.model||""))?.name||app.bridge.embedModel}}if(showToast)toast(app.bridge.ollama?"Ollama está listo.":"Conector disponible; Ollama no está listo.")}catch(error){app.bridge.connected=false;app.bridge.paired=false;app.bridge.ollama=false;app.bridge.error=friendlyError(error);if(showToast)toast(app.bridge.error)}finally{updateStatusUI();if(app.activeTab==="settings")renderSettings()}}
  async function pairBridge(){const code=document.getElementById("skPairCode")?.value.trim();if(!code){toast("Escribe el código mostrado por el conector local.");return}try{const result=await bridge.pair(code);if(!result.token)throw new Error("El conector no devolvió un token.");setToken(result.token);app.bridge.paired=true;toast("SAKURA quedó emparejada con esta plataforma.");await checkBridge(false)}catch(error){toast(friendlyError(error))}}
  async function releaseModel(){try{await bridge.release(app.bridge.chatModel);toast("Modelo liberado de la memoria.")}catch(error){toast(friendlyError(error))}}

  function speak(text,force=false){if(!force&&!app.preferences.voice)return;if(!("speechSynthesis" in window))return;const cleaned=String(text||"").replace(/https?:\/\/\S+/g,"enlace").replace(/[`*_#|<>]/g," ").replace(/SAKURA/gi,"Sakura").slice(0,1800);speechSynthesis.cancel();const utter=new SpeechSynthesisUtterance(cleaned),voices=speechSynthesis.getVoices(),selected=voices.find(v=>v.name===app.preferences.voiceName)||voices.find(v=>/^es-(PE|MX|ES|US)/i.test(v.lang)&&/female|mujer|paulina|sabina|helena|elvira|monica|dalia|sofia/i.test(v.name))||voices.find(v=>/^es/i.test(v.lang));if(selected)utter.voice=selected;utter.lang=selected?.lang||"es-PE";const tone=app.preferences.tone;utter.rate=tone==="calm"?.89:tone==="executive"?1.03:.96;utter.pitch=tone==="warm"?1.08:tone==="executive"?.98:1.04;utter.volume=.92;utter.onstart=()=>setPresence("speaking");utter.onend=()=>setPresence(app.bridge.ollama?"idle":"offline");speechSynthesis.speak(utter)}
  function startListening(){const Recognition=window.SpeechRecognition||window.webkitSpeechRecognition;if(!Recognition){toast("Este navegador no permite reconocimiento de voz local. Puedes escribir el mensaje.");return}const rec=new Recognition();rec.lang="es-PE";rec.interimResults=false;rec.continuous=false;setPresence("listening");rec.onresult=e=>{document.getElementById("skInput").value=e.results[0][0].transcript;sendInput()};rec.onerror=()=>{toast("No pude escuchar con claridad.");setPresence(app.bridge.ollama?"idle":"offline")};rec.onend=()=>setPresence(app.bridge.ollama?"idle":"offline");rec.start()}

  document.addEventListener("sakura:style-applied",event=>{const style=event.detail||{};const panel=document.getElementById("sakuraNativePanel");if(panel){panel.dataset.panelMode=style.panelMode||"normal";panel.dataset.mobileHeight=style.mobileHeight||"70";panel.dataset.frameStyle=style.frameStyle||"minimal";panel.dataset.headerAlign=style.headerAlign||"left";panel.dataset.orbPosition=style.orbPosition||"left"}}, {passive:true});

